#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        int fives=0, tens=0; int ok=1;
        for(int i=0;i<n;i++){
            int bill; scanf("%d", &bill);
            if(bill==5){
                fives++;
            }else if(bill==10){
                if(fives==0) ok=0;
                else{ fives--; tens++; }
            }else{ // bill == 20
                if(tens>0 && fives>0){ tens--; fives--; }
                else if(fives>=3){ fives-=3; }
                else ok=0;
            }
        }
        printf("%s\n", ok?"true":"false");
    }
    return 0;
}

