    while(T--){
        int n; cin>>n;
        int fives=0, tens=0; bool ok=true;
        for(int i=0;i<n;i++){
            int bill; cin>>bill;
            if(bill==5){
                ++fives;
            }else if(bill==10){
                if(fives==0) ok=false;
                else{ --fives; ++tens; }
            }else{ // 20
                if(tens>0 && fives>0){ --tens; --fives; }
                else if(fives>=3){ fives-=3; }
                else ok=false;
            }
        }
        cout << (ok?"true":"false") << '\n';
    }
    return 0;
}

