import sys

def can_provide_change(bills):
    fives = tens = 0
    for bill in bills:
        if bill == 5:
            fives += 1
        elif bill == 10:
            if fives == 0:
                return False
            fives -= 1
            tens += 1
        else:  # 20
            if tens > 0 and fives > 0:
                tens -= 1
                fives -= 1
            elif fives >= 3:
                fives -= 3
            else:
                return False
    return True

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
it = iter(data)
T = int(next(it))
out = []
for _ in range(T):
    n = int(next(it))
    bills = [int(next(it)) for _ in range(n)]
    out.append('true' if can_provide_change(bills) else 'false')
print('\n'.join(out))

